#include <iostream>
#include <vector>

using namespace std;

long long fibonacci(int n)
{
    vector<long long> table(n + 1);
    table[0] = 0;
    if (n >= 1) table[1] = 1;

    for (int i = 2; i <= n; i++) // build UP from the base cases
    {
        table[i] = table[i - 1] + table[i - 2];
    }

    return table[n];
}

int main()
{
    cout << fibonacci(40) << endl;

    return 0;
}

