#include <iostream>

using namespace std;

int climbStairs(int n)
{
    if (n <= 2) return n;

    int prev2 = 1, prev1 = 2;
    for (int i = 3; i <= n; i++)
    {
        int current = prev1 + prev2;
        prev2 = prev1;
        prev1 = current;
    }
    return prev1;
}

int main()
{
    cout << climbStairs(5);

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int minCostClimbingStairs(vector<int>& cost)
{
    int n = cost.size();
    vector<int> table(n + 1);
    table[0] = 0;
    table[1] = 0;

    for (int i = 2; i <= n; i++)
        table[i] = min(table[i - 1] + cost[i - 1], table[i - 2] + cost[i - 2]);

    return table[n];
}

int main()
{
    vector<int> cost = {10, 15, 20};
    cout << minCostClimbingStairs(cost);

    return 0;
}

